public class CottageTown {

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);

        String[] in = sc.nextLine().split(" ");
        int n = Integer.parseInt(in[0]);
        int t = Integer.parseInt(in[1]);

        int[] coor = new int[n];
        int[] side = new int[n];

        for (int i = 0; i < n; i++) {
            in = sc.nextLine().split(" ");
            coor[i] = Integer.parseInt(in[0]);
            side[i] = Integer.parseInt(in[1]);
        }

        quickSort(coor, 0, n - 1, side);

        int count = 2;
        double dist;
        for (int i = 0; i < n - 1; i++) {
            dist = (coor[i + 1] - coor[i]) - (double)(side[i + 1] + side[i]) / 2.0;
            if (dist > t) {
                count += 2;
            } else if (dist == t) {
                count += 1;
            }
        }

        System.out.println(count);

    }

    private static int partition(int[] arr, int left, int right, int[] temp) {
        int i = left, j = right;
        int tmp;
        int pivot = arr[(left + right) / 2];

        while (i <= j) {
            while (arr[i] < pivot) {
                i++;
            }
            while (arr[j] > pivot) {
                j--;
            }
            if (i <= j) {
                tmp = arr[i];
                arr[i] = arr[j];
                arr[j] = tmp;

                tmp = temp[i];
                temp[i] = temp[j];
                temp[j] = tmp;

                i++;
                j--;
            }
        }

        return i;
    }

    private static void quickSort(int[] arr, int left, int right, int[] temp) {
        int index = partition(arr, left, right, temp);
        if (left < index - 1) {
            quickSort(arr, left, index - 1, temp);
        }
        if (index < right) {
            quickSort(arr, index, right, temp);
        }
    }
}

import java.util.Scanner;


public class Flatwile {

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt();
        int t = sc.nextInt();
        int[] c = new int[n];
        int[] a = new int[n];
        for (int i=0; i<n; i++){
            c[i] = sc.nextInt();
            a[i] = sc.nextInt();
        }
        sort(c, a);
        int res = 1;
        double prev = Integer.MIN_VALUE;
        for(int i=0; i<c.length; i++){
            if (c[i]-a[i]/2d - prev >=t){
                res++;
            }
            if (i!=c.length-1 && c[i+1]-a[i+1]/2d-(c[i]+a[i]/2d)>t ){
                res++;
            }
            prev = c[i] +a[i]/2d;
        }
        System.out.println(res);
    }

    private static void sort(int[] a, int[] b){
        for(int i=0; i<a.length; i++){
            for(int j=i+1; j<a.length; j++){
                if (a[i]>a[j]){
                    swap(a, i, j);
                    swap(b, i, j);
                }
            }
        }
    }

    private static void swap(int[] a, int i, int j) {
        int t = a[i];
        a[i] = a[j];
        a[j] = t;
    }

}

import java.util.Scanner;

public class A {
    public static void main(String[] args) {
        new A().solve();
    }

    public void solve() {
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt();
        int t = sc.nextInt();
        float[] left = new float[n];
        float[] right = new float[n];
        for (int i=0; i<n; ++i) {
            int c = sc.nextInt();
            int w = sc.nextInt();
            left[i] = (float) (c - (float) w * 1.0 / 2);
            right[i] = (float) (c + (float) w * 1.0 / 2);
        }
        for (int i=0; i<n; ++i)
            for (int j=i+1; j<n; ++j)
                if (left[j] < left[i]) {
                    float tmp = left[i];
                    left[i] = left[j];
                    left[j] = tmp;
                    tmp = right[i];
                    right[i] = right[j];
                    right[j] = tmp;
                }
        int res = 2;
        for (int i=1; i<n; ++i) {
            float dis = left[i] - right[i-1];
            if (Math.abs(dis - t) < 0.000001)
                res ++;
            if ((dis - t) > 0.000001)
                res += 2;
        }
        System.out.println(res);
    }
}

