class ArrayColumnComparator implements Comparator {
    private int cm = 0;
    ArrayColumnComparator(int cm) {
        this.cm = cm;
    }
    public int compare(Object o1, Object o2) {
        double[] row1 = (double[])o1;
        double[] row2 = (double[])o2;
