public class Main implements Runnable {

	class Segment {
		int l, r;
		Segment(int l, int r) {
			this.l = l;
			this.r = r;
		}
		@Override
		public boolean equals(Object obj) {
			Segment o = (Segment)obj;
			return l == o.l && r == o.r;
		}
		@Override
		public int hashCode() {
			return 1000 * l + r;
		}
	}

	public void _main() throws IOException {
		int n = nextInt();
		int t = nextInt();
		int[] x = new int[n];
		int[] a = new int[n];
		for (int i = 0; i < n; i++) {
			x[i] = nextInt();
			a[i] = nextInt();
		}		
		Set<Segment> set = new HashSet<Segment>();
		for (int i = 0; i < n; i++) {
			int l = 2 * x[i] + a[i];
			int r = 2 * x[i] + a[i] + 2 * t;
			boolean ok = true;
			for (int j = 0; j < n; j++) {
				if (i == j) continue;
				int L = Math.max(l, 2 * x[j] - a[j]);
				int R = Math.min(r, 2 * x[j] + a[j]);				
				if (L < R) {
					ok = false;
					break;
				}
			}
			if (ok)
				set.add(new Segment(l, r));

			l = 2 * x[i] - a[i] - 2 * t;
			r = 2 * x[i] - a[i];			
			ok = true;
			for (int j = 0; j < n; j++) {
				if (i == j) continue;
				int L = Math.max(l, 2 * x[j] - a[j]);
				int R = Math.min(r, 2 * x[j] + a[j]);
				if (L < R) {
					ok = false;
					break;
				}
			}
			if (ok)
				set.add(new Segment(l, r));
		}
		out.print(set.size());
	}

