        int n = in.nextInt();
        int[] a = new int[n];
        int all = 0;
        for (int i = 0; i < n; ++i) {
            a[i] = in.nextInt();
            all += a[i];
        }
        Arrays.sort(a);
        int sum = 0, ans = 0;
        for (int i = n - 1; i >= 0; --i) {
            sum += a[i];
            ++ans;
            if (sum > all - sum) {
                break;
            }
        }
        out.println(ans);
    }

