		int[] a = new int[n];
		int sum = 0;
		for (int i = 0; i < n; i++) {
			a[i] = readInt();
			sum += a[i];
		}
		Utils.mergeSort(a);
		int s = 0, c = 0;
		for (int i = n-1; i >= 0; i--) {
			s += a[i];
			c++;
			if (2 * s > sum) {
				break;
			}
		}
		out.println(c);

	}

}

