        int x;
        int y;

            public Lol (int x , int y){
                this.x = x;
                this.y = y;
            }

            @Override
            public int compareTo(Lol arg0) {
                if (arg0.x == x) {
                    return y-arg0.y;
                }
                return arg0.x-x;
            }

    }

    public void solve() throws IOException {

        int n = readInt();
        int k = readInt();
        k--;
        Lol [] a = new Lol [n];

        for (int i  = 0 ; i  <n; i++){
            int x = readInt();
