        }
        Arrays.sort(a);
        int ans = 1; 
        for (int i =k+1; i>-1; i++){
            if (i==n) break;
            if (a[i].x==a[k].x && a[i].y == a[k].y){
                ans++;
            }
            else break;
        }
        if (k!=0){
            for (int i =k-1; i>=0; i--){
                if (a[i].x==a[k].x && a[i].y == a[k].y){
                    ans++;
                }
                else break;
            }
        }
        out.print(ans);



    }
}

