        final int[] p = new int[n];
        final int[] t = new int[n];
        for(int i =0 ; i < n; ++i) {
            p[i] = in.nextInt();
            t[i] = in.nextInt();
        }
        Integer[] ord = new Integer[n];
        for(int i = 0; i < n; ++i)
            ord[i] = i;
        for(int i = 0; i < n; ++i) {
            for(int j = 0; j < n - 1; ++j) {
                if (Less(ord[j], ord[j + 1], p, t)) {
                    Integer tx = ord[j];
                    ord[j] = ord[j + 1];
                    ord[j + 1] = tx;
                }
            }
        }



        for(int i = 0, j = 0; i < n; i = j) {
            for(j = i; j < n && p[ord[i]] == p[ord[j]] && t[ord[i]] == t[ord[j]]; ++j) ;
