			a[i] = ac[i] = sc.nextInt();
		}
		randomShuffle(ac);
		Arrays.sort(ac);
		int diff = 0;
		for (int i = 0; i < n; i++) {
			if (a[i] != ac[i]) {
				diff++;
			}
		}
		if (diff <= 2) {
