public class Codeforces_R136_Div1_A implements Runnable{

	private void solve() throws IOException {
		int n = scanner.nextInt();
		int[] a = new int[n];
		for (int i = 0; i < a.length; i++) {
			a[i] = scanner.nextInt();
		}

		boolean sorted = true;
		for (int i = 0; i < a.length; i++) {
			if (!isOk(a, i)){
				sorted = false;
			}
		}
		if (sorted){
			out.println("YES");
			return;
		}

		List<Integer> idx = new ArrayList<Integer>();		
		for(int i=0; i<n; i++){
			if (!isOk(a, i)){		
				idx.add(i);								
			}
		}

		if (idx.size() > 6){
			out.println("NO");
			return;
		}

		for(int i=0; i<idx.size(); i++){
			for(int j=0; j<n; j++){
				swap(a, idx.get(i), j);
				if (isOk(a, idx) && isOk(a, j)){
					out.println("YES");
					return;
				}
				swap(a, idx.get(i), j);
			}
		}
		out.println("NO");				
	}

	private boolean isOk(int[] a, int i) {		
		boolean ordered = true; 
		if (i>0 && !(a[i-1] <= a[i])){
			ordered = false;
		}
		if (i<a.length-1 && !(a[i]<=a[i+1])){
			ordered = false;
		}
		return ordered;
	}

	private boolean isOk(int[] a, List<Integer> idx) {
		for(int i : idx){
			if (!isOk(a, i))
				return false;
		}
		return true;
	}

	private void swap(int[] a, int i, int j) {
		int tmp = a[i];
		a[i] = a[j];
		a[j] = tmp;
	}


	/////////////////////////////////////////////////
	final int BUF_SIZE = 1024 * 1024 * 8;//important to read long-string tokens properly
