        int n = nextInt();
        int k = nextInt();
        int[] a = new int[n];
        for (int i = 0; i < n; i++) {
            a[i] = nextInt();
        }
        boolean[] ok = new boolean[n];
        Arrays.fill(ok, true);
        Arrays.sort(a);
