                if (a[i] % k == 0) {
                    int x = a[i] / k;
                    int ind = Arrays.binarySearch(a, x);
                    if (ind >= 0 && ok[ind]) {
                        ok[i] = false;
                    }
                }
            }
        }
        int ans = 0;
        for (int i = 0; i < n; i++) {
            if (ok[i]) {
                ans++;
            }
        }
        out.println(ans);
    }

