class ArrayShuffler {
    static Random random = new Random(7428429L);

    public void shuffle(long[] p) {
        for (int i = 0; i < p.length; ++i) {
            int j = i + random.nextInt(p.length - i);
            long temp = p[i];
            p[i] = p[j];
            p[j] = temp;
        }
    }

    }

