	static class MultiTreeSet<T extends Comparable<T>> {
		private TreeMap<T, Integer> map = new TreeMap<>();

		public int count(T x) {
			Integer ret = map.get(x);
			return ret == null ? 0 : ret;
		}

		void add(T x) {
			map.put(x, count(x) + 1);
		}

		T first() {
			return map.firstKey();
		}

		T last() {
			return map.lastKey();
		}

		boolean remove(T x) {
			int prev = count(x);
			if (prev == 0) {
				return false;
			}
			if (prev == 1) {
				map.remove(x);
			} else {
				map.put(x, prev - 1);
			}
			return true;
		}
	}

	void go(int x, TreeSet<Integer> pos, MultiTreeSet<Integer> sz,
			MultiTreeSet<Integer> otherSz) {
		if (!pos.contains(x)) {
			int prev = pos.lower(x);
			int next = pos.higher(x);
			sz.remove(next - prev);
			sz.add(x - prev);
			sz.add(next - x);
			pos.add(x);
		}
		long ret = (long) sz.last() * otherSz.last();
		out.println(ret);
	}

