		szH.add(h);
		for (int i = 0; i < n; i++) {
			char type = nextToken().charAt(0);
			int x = nextInt();
			if (type == 'H') {
				go(x, hh, szH, szW);
			} else {
				go(x, ww, szW, szH);
			}
		}
	}

