				int rightY = yCuts.ceiling(y);

				int delta = rightY - leftY;
				dec(hMultiSet, delta);

				yCuts.add(y);
				inc(hMultiSet, y - leftY);
				inc(hMultiSet, rightY - y);
			} else {
				int x = coordinate;

				int leftX = xCuts.floor(x);
				int rightX = xCuts.ceiling(x);

				int delta = rightX - leftX;
				dec(wMultiSet, delta);

				xCuts.add(x);
				inc(wMultiSet, x - leftX);
				inc(wMultiSet, rightX - x);
			}

			long maxWDelta = wMultiSet.lastKey();
			long maxHDelta = hMultiSet.lastKey();

			out.println(maxWDelta * maxHDelta);
		}
