	void inc(Map<Integer, Integer> multiSet, int value) {
		Integer count = multiSet.get(value);
		if (count == null) {
			multiSet.put(value, 1);
		} else {
			multiSet.put(value, count + 1);
		}
	}

	void dec(Map<Integer, Integer> multiSet, int value) {
		Integer count = multiSet.get(value);
		if (count == 1) {
			multiSet.remove(value);
		} else {
			multiSet.put(value, count - 1);
		}
	}
