		}
	}

	static Comparator<Segment> byL = (Segment a, Segment b) -> {
		if (a.l != b.l) {
			return a.l < b.l ? -1 : 1;
		}
		return Integer.compare(a.id, b.id);
	};

	static Comparator<Segment> byR = (Segment a, Segment b) -> {
		if (a.r != b.r) {
			return a.r < b.r ? -1 : 1;
		}
		return Integer.compare(a.id, b.id);
	};

