		HashMap<Integer, Integer> freq = new HashMap<>();
		for(int i = 0; i < n; ++i) {
			a[i] = in.nextInt();
			freq.put(a[i], 0);
			freq.put(a[i] + 1, 0);
			freq.put(a[i] - 1, 0);
		}
		long sum = 0;
		BigInteger ans = new BigInteger("0");
		for(int i = n - 1; i >= 0; --i) {
			long num = n - 1 - i;
			long add = sum - num * a[i];
			add -= freq.get(a[i] + 1);
			add += freq.get(a[i] - 1);
			BigInteger biadd = new BigInteger("" + add);
			ans = ans.add(biadd);
			sum += a[i];
			freq.put(a[i], freq.get(a[i]) + 1);
		}
