    	}
    }

    class FenwickTree {
    	int n;
    	int[] tree;

    	public FenwickTree(int n) {
    		this.n = n;
    		tree = new int[n];
    	}

    	public int sum(int id) {
    		int res = 0;
    		while (id > 0) {
    			res += tree[id];
    			id -= id & -id;
    		}
    		return res;
    	}

    	public void add(int id, int v) {
    		while (id < n) {
    			tree[id] += v;
    			id += id & -id;
    		}
    	}

    	int findkth(int k) {
    		int low = 1, high = n;
    		while (low < high) {
    			int mid = (low + high) / 2;
    			int val = sum(mid);
    			if(val < k) low = mid + 1;
    			else high = mid;
    		}
    		return low;
    	}
    }


