	class Pair implements Comparable<Pair> {
		int val, id;
		Pair (int a, int b) {
			val = a;
			id = b;
		}

		public int compareTo (Pair o) {
			if(val == o.val) return Integer.compare(id, o.id);
			return Integer.compare(o.val, val);
		}
	}

	class Fenwick_Tree {

		long[] bit;
		int n;

		public Fenwick_Tree(int a) {
			n = a + 1;
			bit = new long[n];
		}

		//Remember that when querying a sum to query the 1-based index of the value.

		void update (int index, long val) {
			while(index < n) {
				bit[index] += val;
				index += (index & (-index));
			}
		}

		long sum (int index) {
			long sum = 0;
			while(index > 0) {
				sum += bit[index];
				index -= (index & (-index));
			}
			return sum;
		}
	}


