	void solve()
	{
		int n = ni(), m = ni();
		long B = nl(), I = nl(), D = nl();
		long[][] ens = new long[n][];
		for(int i = 0;i < n;i++){
			ens[i] = new long[]{nl(), nl(), nl()};
		}
		long[][] ups = new long[m][];
		for(int i = 0;i < m;i++){
			ups[i] = new long[]{nl(), nl()-1, nl()};
		}

		PriorityQueue<long[]> pq = new PriorityQueue<>(
				(x, y) -> Long.compare(x[0], y[0]));
		pq.add(new long[]{0L, -1});
		pq.add(new long[]{1L<<32, -1});
		for(long[] u : ups){
			pq.add(u);
			if(u[0] >= 1)pq.add(new long[]{u[0]-1, u[1]});
		}
		long vanish = 0;
		for(int i = 0;i < n;i++){
			long[] en = ens[i];
			if(en[1] <= D && en[0] > D && en[2] > 0){
				// en[1] + t*en[2] <= D
				pq.add(new long[]{(D-en[1])/en[2], i});
				pq.add(new long[]{(D-en[1])/en[2]+1, i});
			}
			if(en[1] <= D){
				vanish++;
			}
		}

		long ans = 0;
		long[] last = new long[n];
		while(!pq.isEmpty()){
			long[] cur = pq.poll();
			long t = cur[0];
			int ind = (int)cur[1];
			if(ind != -1){
				if(ens[ind][1] <= D){vanish--;}
				if(cur.length == 2){
					ens[ind][1] = Math.min(ens[ind][0], ens[ind][1] + ens[ind][2] * (t - last[ind]));
				}else{
					ens[ind][1] = cur[2];
					long[] en = ens[ind];
					if(en[1] <= D && en[0] > D && en[2] > 0){
						// en[1] + t*en[2] <= D
						pq.add(new long[]{(D-en[1])/en[2]+t, ind});
						pq.add(new long[]{(D-en[1])/en[2]+t+1, ind});
					}
				}
				if(ens[ind][1] <= D){vanish++; }

				last[ind] = t;
			}

			if(!pq.isEmpty() && pq.peek()[0] != t){
				ans = Math.max(ans, (B+t*I)*vanish);
			}
		}
		if(I > 0 && vanish > 0){
			out.println(-1);
		}else{
			out.println(ans);
		}
	}

	public static class MinHeapL {
		public long[] a;
		public int[] map;
		public int[] imap;
		public int n;
		public int pos;
		public static long INF = Long.MAX_VALUE;

		public MinHeapL(int m)
		{
			n = Integer.highestOneBit((m+1)<<1);
			a = new long[n];
			map = new int[n];
			imap = new int[n];
			Arrays.fill(a, INF);
			Arrays.fill(map, -1);
			Arrays.fill(imap, -1);
			pos = 1;
		}

		public long add(int ind, long x)
		{
			int ret = imap[ind];
			if(imap[ind] < 0){
				a[pos] = x; map[pos] = ind; imap[ind] = pos;
				pos++;
				up(pos-1);
			}
			return ret != -1 ? a[ret] : x;
		}

		public long update(int ind, long x)
		{
			int ret = imap[ind];
			if(imap[ind] < 0){
				a[pos] = x; map[pos] = ind; imap[ind] = pos;
				pos++;
				up(pos-1);
			}else{
				a[ret] = x;
				up(ret);
				down(ret);
			}
			return x;
		}

		public long remove(int ind)
		{
			if(pos == 1)return INF;
			if(imap[ind] == -1)return INF;

			pos--;
			int rem = imap[ind];
			long ret = a[rem];
			map[rem] = map[pos];
			imap[map[pos]] = rem;
			imap[ind] = -1;
			a[rem] = a[pos];
			a[pos] = INF;
			map[pos] = -1;

			up(rem);
			down(rem);
			return ret;
		}

		public long min() { return a[1]; }
		public int argmin() { return map[1]; }
		public int size() {	return pos-1; }

		private void up(int cur)
		{
			for(int c = cur, p = c>>>1;p >= 1 && a[p] > a[c];c>>>=1, p>>>=1){
				long d = a[p]; a[p] = a[c]; a[c] = d;
				int e = imap[map[p]]; imap[map[p]] = imap[map[c]]; imap[map[c]] = e;
				e = map[p]; map[p] = map[c]; map[c] = e;
			}
		}

		private void down(int cur)
		{
			for(int c = cur;2*c < pos;){
				int b = a[2*c] < a[2*c+1] ? 2*c : 2*c+1;
				if(a[b] < a[c]){
					long d = a[c]; a[c] = a[b]; a[b] = d;
					int e = imap[map[c]]; imap[map[c]] = imap[map[b]]; imap[map[b]] = e;
					e = map[c]; map[c] = map[b]; map[b] = e;
					c = b;
				}else{
					break;
				}
			}
		}
	}	
