		int another[]=new int[n];
		for(int i=0;i<n;i++) {
			int ai=sc.nextInt();
			int time=sc.nextInt();
			arr[i]=new Pair(ai, time, i+1);
		}
		sort(arr);
		for(int i=0;i<n;i++) {
			another[i]=arr[i].a;
		}
		int maxscore=0;
		int maxai=n+1;
		int start=1;
		int end=n;
		while(start<=end) {
			int mid=start+(end-start)/2;
			int index=LowerBound(another, mid);
			PriorityQueue<Integer> pq=new PriorityQueue<Integer>((a,b)->(a-b));
			for(int i=index;i<n;i++) {
				pq.add(arr[i].time);
			}
			int maxtime=t;
			int score=0;
			while(maxtime>0 && !pq.isEmpty()) {
				maxtime -= pq.poll();
				if(maxtime>=0) score++;
			}
			if(score>=mid) {
				if(mid>=maxscore) {
					maxscore=mid;
					maxai=mid;
				}
				start=mid+1;
			}
			else {
				end=mid-1;
			}

		}

		int index=LowerBound(another, maxai);
