	public static class SegmentTreeOverwrite {
		public int M, H, N;
		public int[] sums;
		public int[] cover;
		public int[] cums;
		public int I = Integer.MAX_VALUE;

		public SegmentTreeOverwrite(int[] w)
		{
			N = w.length;

			M = Integer.highestOneBit(Math.max(N-1, 1))<<2;
			H = M>>>1;
			cover = new int[M];
			sums = new int[M];
			Arrays.fill(cover, I);
			for(int i = 0;i < N;i++){
				cover[H+i] = 1;
				sums[H+i] = w[i];
			}
			cums = new int[H+1];
			for(int i = 0;i < H;i++){
				cums[i+1] = cums[i] + (i < N ? w[i] : 0);
			}

			for(int i = H-1;i >= 1;i--){
				propagate(i);
			}
		}

		private void propagate(int i){
			if(cover[i] == I){
				sums[i] = sums[2*i] + sums[2*i+1];
			}else if(cover[i] == 1){
				int h = Integer.highestOneBit(i);
				int ind = i - h;
				int seg = H/h;
				sums[i] = cums[seg*(ind+1)] - cums[seg*ind];
			}else{
				sums[i] = 0;
			}
		}

		public void update(int l, int r, int v){ update(l, r, v, 0, H, 1); }

		private void update(int l, int r, int v, int cl, int cr, int cur)
		{
			if(l <= cl && cr <= r){
				cover[cur] = v;
				propagate(cur);
			}else{
				int mid = cl+cr>>>1;
				if(cover[cur] != I){ // back-propagate
					cover[2*cur] = cover[2*cur+1] = cover[cur];
					cover[cur] = I;
					propagate(2*cur);
					propagate(2*cur+1);
				}
				if(cl < r && l < mid){
					update(l, r, v, cl, mid, 2*cur);
				}
				if(mid < r && l < cr){
					update(l, r, v, mid, cr, 2*cur+1);
				}
				propagate(cur);
			}
		}
	}


	public static int[] shrinkX(int[] a) {
		int n = a.length;
		long[] b = new long[n];
		for (int i = 0; i < n; i++)
			b[i] = (long) a[i] << 32 | i;
		b = radixSort(b);
