    PriorityQueue<Integer> dfs(int i, int par) {
        ArrayList<PriorityQueue<Integer>> list = new ArrayList<>();
        PriorityQueue<Integer> largestQueue = new PriorityQueue<>();
        int largestSize = 0;
        for(int j : adj[i]) {
            if(j != par) {
                PriorityQueue<Integer> cur = dfs(j, i);
                if(cur.size() > largestSize) {
                    if(largestSize != 0)
                        list.add(largestQueue);
                    largestQueue = cur;
                    largestSize = cur.size();
                }
                else {
                    list.add(cur);
                }
            }
        }

        if(largestSize == 0) {
            PriorityQueue<Integer> queue = new PriorityQueue<>(new Comparator<Integer>() {
                public int compare(Integer i1, Integer i2) {
                    if(i1 > i2)
                        return -1;
                    if(i1 < i2)
                        return 1;
                    return 0;
                }
            });
            queue.add(1);
            cntLeaf++;
            return queue;
        }

        PriorityQueue<Integer> queue = largestQueue;
        for(int j = 0; j < list.size(); ++j) {
            PriorityQueue<Integer> cur = list.get(j);
            while(cur.size() != 0)
                queue.add(cur.poll());
        } 
        int maxV = queue.poll();
        queue.add(maxV + 1);
        return queue;
    }
    void dfsFindLevel(int i, int par, int level) {
        if(level > maxLevel) {
            maxLevel = level;
            maxNode = i;
        }
        for(int j : adj[i]) {
            if(j != par)
                dfsFindLevel(j, i, level + 1);
        }
    }
    ArrayList<Integer> adj[];
    int cntLeaf = 0;
    int maxLevel = -1, maxNode = -1;
    public void run() {
        InputReader sc = new InputReader(System.in);
        PrintWriter w = new PrintWriter(System.out);

        int n = sc.nextInt();

        adj = new ArrayList[n];
        for(int i = 0; i < n; ++i)
            adj[i] = new ArrayList<>();

        for(int i = 0; i < n - 1; ++i) {
            int u = sc.nextInt() - 1;
            int v = sc.nextInt() - 1;
            adj[u].add(v);
            adj[v].add(u);
        }

        dfsFindLevel(0, -1, 0);

        PriorityQueue<Integer> queue = dfs(maxNode, -1);
        int maxV = queue.poll();
        queue.add(maxV - 1);

        int cans = 1;
        for(int i = 0; i < cntLeaf; ++i) {
            w.print(cans + " ");
            cans += queue.poll();
        }

        for(int i = cntLeaf; i < n; ++i)
            w.print(cans + " ");

        w.close();      
    }
}

