class Solution {
    PrintWriter out;
    int INF = Integer.MAX_VALUE;
    int MOD = 1000000007;
    long mod = 1000000007;

    public Solution(PrintWriter out) {
        this.out = out;
    }

    boolean seen[];
    int graph[][];
    int f[][];
    public void solution(int graph[][],int n,int k) {
        this.graph=graph;
        seen=new boolean[n];
        f=new int[n][20];
        for(int i=0;i<f.length;i++){
            Arrays.fill(f[i],-1);
        }





        dfs(-1,n-1);

        for(int i=1;i<f[0].length;i++){
            for(int j=0;j<n;j++){
                int p = f[j][i-1];
                if(p==-1)continue;
                f[j][i]=f[p][i-1];
            }
        }


        seen[n-1]=true;
        int sum = 1;
        for(int i=n-2;i>=0;i--){
            if(seen[i])continue;
            int cur = i;
            int total=0;
            for(int j=19;j>=0;j--){
                if(f[cur][j]==-1)continue;
                int v = f[cur][j];
                if(seen[v])continue;//tag
                int dis = (1<<j);
                cur = f[cur][j];
                total+=dis;
                if(total+1+sum>n-k)break;
            }

            cur = i;
            if(total+1+sum<=n-k){
                sum+=total+1;
                while(!seen[cur]){
                    seen[cur]=true;
                    cur=f[cur][0];
                }
            }
        }



        for(int i=0;i<seen.length;i++){
            if(!seen[i]){
                out.print((i+1)+" ");
            }
        }
    }

    public void dfs(int p,int root){
        for(int next:graph[root]){
            if(p!=next){
                f[next][0]=root;
                dfs(root,next);
            }
        }
    }


}

import java.io.*;
