    public static boolean bfs(int x, int y, int n, int m, char ch[][]) {
        vis[x][y] = 0;
        Queue<Pair> qu = new LinkedList<>();
        qu.add(new Pair(x, y));
        while (!qu.isEmpty()) {
            Pair p = qu.poll();
            int i = p.a;
            int j = p.b;
            if (i + 1 < n) {
                if (ch[i + 1][j] == '.') {
                    if (vis[i][j] + 1 < vis[i + 1][j]) {
                        vis[i + 1][j] = vis[i][j] + 1;

                        if (i + 1 == n - 1) {
                            xx = i + 1;
                            ch[i + 1][j] = 'D';
                            yy = j;
                            return true;
                        }
                        ch[i + 1][j] = 'D';
                        qu.add(new Pair(i + 1, j));
                    }
                }
            }
            if (j + 1 < m) {
                if (ch[i][j + 1] == '.') {
                    if (vis[i][j] + 1 < vis[i][j + 1]) {
                        vis[i][j + 1] = vis[i][j] + 1;
                        if (j + 1 == m - 1) {
                            xx = i;
                            yy = j + 1;
                            ch[i][j + 1] = 'R';
                            return true;
                        }
                        ch[i][j + 1] = 'R';
                        qu.add(new Pair(i, j + 1));
                    }
                }
            }
            if (i - 1 >= 0) {
                if (ch[i - 1][j] == '.') {
                    if (vis[i][j] + 1 < vis[i - 1][j]) {
                        vis[i - 1][j] = vis[i][j] + 1;
                        if (i - 1 == 0) {
                            xx = i - 1;
                            yy = j;
                            ch[i - 1][j] = 'U';
                            return true;
                        }
                        ch[i - 1][j] = 'U';
                        qu.add(new Pair(i - 1, j));
                    }
                }
            }
            if (j - 1 >= 0) {
                if (ch[i][j - 1] == '.') {

                    if (vis[i][j] + 1 < vis[i][j - 1]) {
                        vis[i][j - 1] = vis[i][j] + 1;
                        if (j - 1 == 0) {
                            yy = j - 1;
                            xx = i;
                            ch[i][j - 1] = 'L';
                            return true;
                        }
                        ch[i][j - 1] = 'L';
                        qu.add(new Pair(i, j - 1));
                    }
                }
            }
        }
        return false;
    }


