public class Solution implements Runnable {

	long mod1 = (long) 1e9 + 7;
	int mod2 = 998244353;

	public void solve() throws Exception {
		int n=sc.nextInt();
		int arr[]=new int[n+1];
		for(int i=1;i<=n;i++) arr[i]=sc.nextInt();
		int indices[]=new int[n+1];
		for(int i=1;i<=n;i++) {
			indices[arr[i]]=i;
		}
		int winorlose[]=new int[n+1];
		winorlose[n] = -1;
		for(int i=n-1;i>=1;i--) {
			int index=indices[i];
			winorlose[i]=-1;

			for(int j=index;j<=n;j+=i) {

				if(arr[j]>i && winorlose[arr[j]]!=0) {
					if(winorlose[arr[j]]==-1) {
						winorlose[i]=1;
					}
				}
			}
			for(int j=index;j>=1;j-=i) {
//				if(i==2) {
//					out.println(j+" "+arr[j]);
//				}
				if(arr[j]>i && winorlose[arr[j]]!=0) {
					if(winorlose[arr[j]]==-1) {
						winorlose[i]=1;
					}
				}
			}
		}
		for(int i=1;i<=n;i++) 
		{
			if(winorlose[arr[i]]==1) {
				out.print("A");
			}
			else out.print("B");
		}
	}

	static void sort(int[] a) {
		ArrayList<Integer> l = new ArrayList<>();
		for (int i : a)
			l.add(i);
		Collections.sort(l);
		for (int i = 0; i < a.length; i++)
			a[i] = l.get(i);
	}

	static long gcd(long a, long b) {
		if (a == 0)
			return b;
		return gcd(b % a, a);
	}

	static long ncr(int n, int r, long p) {
		if (r > n)
			return 0l;
		if (r > n - r)
			r = n - r;

		long C[] = new long[r + 1];

		C[0] = 1;

		for (int i = 1; i <= n; i++) {

			for (int j = Math.min(i, r); j > 0; j--)
				C[j] = (C[j] + C[j - 1]) % p;
		}
		return C[r] % p;
	}

	public long power(long x, long y, long p) {
		long res = 1;
		// out.println(x+" "+y);
		x = x % p;
		if (x == 0)
			return 0;

		while (y > 0) {
			if ((y & 1) == 1)
				res = (res * x) % p;
			y = y >> 1;
			x = (x * x) % p;
		}
		return res;
	}

	static Throwable uncaught;

	BufferedReader in;
	FastScanner sc;
	PrintWriter out;

	@Override
	public void run() {
		try {
			in = new BufferedReader(new InputStreamReader(System.in));
			out = new PrintWriter(System.out);
			sc = new FastScanner(in);
			solve();
		} catch (Throwable uncaught) {
			Solution.uncaught = uncaught;
		} finally {
			out.close();
		}
	}

	public static void main(String[] args) throws Throwable {
		Thread thread = new Thread(null, new Solution(), "", (1 << 26));
		thread.start();
		thread.join();
		if (Solution.uncaught != null) {
			throw Solution.uncaught;
		}
	}

}

