			tree[nI][0] = nLoc[cL];
			tree[nI][1] = nLoc[cL];
		} else {
			int mid = (cL + cR) >> 1;
			build(nI * 2, cL, mid);
			build(nI * 2 + 1, mid + 1, cR);
			if (tree[nI * 2][0] != -1 && tree[nI * 2 + 1][0] != -1) {
				merge(tree[nI * 2][0], tree[nI * 2][1], tree[nI * 2 + 1][0], tree[nI * 2 + 1][1]);
				tree[nI][0] = mResp[0];
				tree[nI][1] = mResp[1];
			}
		}
	}

	static int query(int nI, int cL, int cR, int e1, int e2) {
		if (cL == cR) {
			merge(e1, e2, nLoc[cL], nLoc[cL]);
			if (mResp[0] != -1) {
				return cL;
			} else {
				return cL - 1;
			}
		}
		int mid = (cL + cR) >> 1;

		merge(tree[nI * 2][0], tree[nI * 2][1], e1, e2);
		if (mResp[0] != -1) {
			return query(nI * 2 + 1, mid + 1, cR, mResp[0], mResp[1]);
		}
		return query(nI * 2, cL, mid, e1, e2);
	}

	static void update(int nI, int cL, int cR, int uI) {
		if (cL == cR) {
			tree[nI][0] = nLoc[cL];
			tree[nI][1] = nLoc[cL];
		} else {
			int mid = (cL + cR) >> 1;
			if (uI <= mid) {
				update(nI * 2, cL, mid, uI);
			} else {
				update(nI * 2 + 1, mid + 1, cR, uI);
			}
			merge(tree[nI * 2][0], tree[nI * 2][1], tree[nI * 2 + 1][0], tree[nI * 2 + 1][1]);
			tree[nI][0] = mResp[0];
			tree[nI][1] = mResp[1];
		}
	}

	static int[] mResp = new int[2];

	static void merge1(int... a) {
		for (int i = 0; i < 3; i++) {
			if (a[i] == -1) {
				mResp[0] = mResp[1] = -1;
				return;
			}
		}

		if (onPath(a[0], a[1], a[2])) {
			mResp[0] = a[0];
			mResp[1] = a[1];
			return;
		}
		if (onPath(a[0], a[2], a[1])) {
			mResp[0] = a[0];
			mResp[1] = a[2];
			return;
		}
		if (onPath(a[1], a[2], a[0])) {
			mResp[0] = a[1];
			mResp[1] = a[2];
			return;
		}
		mResp[0] = mResp[1] = -1;
	}

	static void merge(int... a) {
		merge1(a[0], a[1], a[2]);
		merge1(mResp[0], mResp[1], a[3]);
	}

	static boolean onPath(int a, int b, int c) {
		if (a == c || b == c) {
			return true;
		}

		if (depth[a] > depth[c]) {
			a = jump(a, depth[a] - depth[c] - 1);
		}
		if (depth[b] > depth[c]) {
			b = jump(b, depth[b] - depth[c] - 1);
		}
		if (a == b) {
			return false;
		}

		if (anc[a][0] == c || anc[b][0] == c) {
			return true;
		}

		return false;
	}

	// good for depth of up to 1_048_576 = 2^20

	static void preprocess() {
		anc[root][0] = root;
		fParent(root);

		for (int k = 1; k <= 20; k++) {
			for (int i = 0; i < nV; i++) {
				anc[i][k] = anc[anc[i][k - 1]][k - 1];
			}
		}
	}

	static void fParent(int cV) {
		for (int aV : chldn[cV]) {
			anc[aV][0] = cV;
			depth[aV] = depth[cV] + 1;
			fParent(aV);
		}
	}

	static int fLCA(int a, int b) {
		if (depth[a] > depth[b]) {
			int temp = b;
			b = a;
			a = temp;
		}
		b = jump(b, depth[b] - depth[a]);
		if (a == b) {
			return a;
		}
		for (int i = 20; i >= 0; i--) {
			if (anc[a][i] != anc[b][i]) {
				a = anc[a][i];
				b = anc[b][i];
			}
		}
		return anc[a][0];
	}

	static int jump(int cV, int d) {
		for (int i = 0; i <= 20; i++) {
			if ((d & (1 << i)) != 0) {
				cV = anc[cV][i];
			}
		}
		return cV;
	}

	static Comparator<Integer> BY_DEPTH = new Comparator<Integer>() {
		public int compare(Integer o1, Integer o2) {
			return -Integer.compare(depth[o1], depth[o2]); // greatest depth first
		}
	};
}

import java.io.*;
import java.util.*;

public class F {
    public static void main(String[] args) throws IOException {
        try (Input input = new StandardInput(); PrintWriter writer = new PrintWriter(System.out)) {
            int n = input.nextInt();
            int[] p = new int[n + 1];
            for (int i = 1; i <= n; i++) {
                p[i] = input.nextInt();
            }
            int[] parent = new int[n + 1];
            int[] childrenCount = new int[n + 1];
            for (int u = 2; u <= n; u++) {
                parent[u] = input.nextInt();
                childrenCount[parent[u]]++;
            }
            int[][] g = new int[n + 1][];
            for (int i = 1; i <= n; i++) {
                g[i] = new int[childrenCount[i]];
                childrenCount[i] = 0;
            }
            for (int u = 2; u <= n; u++) {
                int v = parent[u];
                g[v][childrenCount[v]++] = u;
            }
            class Path {
                final int v1, v2, lca;

                Path(int v1, int v2, int lca) {
                    this.v1 = v1;
                    this.v2 = v2;
                    this.lca = lca;
                }

                private boolean isVertical() {
                    return lca == v1 || lca == v2;
                }

                private int getLeft() {
                    return v1 == lca ? v2 : v1;
                }

                private int getRight() {
                    return v2;
                }

                @Override
                public String toString() {
                    if (lca == v1) {
                        return String.format("%d->%d", v1, v2);
                    }
                    return String.format("%d->(%d)->%d", v1, lca, v2);
                }
            }
            class LCA {
                private final int[] enter = new int[n + 1];
                private final int[] leave = new int[n + 1];
                private final int[] timeline = new int[2 * n];
                private int time = 0;

                private void dfs(int u) {
                    enter[u] = time;
                    timeline[time++] = u;
                    for (int v : g[u]) {
                        dfs(v);
                        timeline[time++] = u;
                    }
                    leave[u] = time;
                }

                {
                    dfs(1);
                }

                class SegmentTree {
                    int size = 1;
                    {
                        while (size <= timeline.length) {
                            size *= 2;
                        }
                    }
                    final int[] a = new int[2 * size];
                    {
                        enter[0] = Integer.MAX_VALUE;
                        System.arraycopy(timeline, 0, a, size, time);
                        for (int i = size - 1; i > 0; i--) {
                            int left = a[2 * i];
                            int right = a[2 * i + 1];
                            a[i] = enter[left] < enter[right] ? left : right;
                        }
                    }

                    int getLCA(int v1, int v2) {
                        int from = Math.min(enter[v1], enter[v2]);
                        int to = enter[v1] + enter[v2] - from;
                        int lca = 0;
                        for (from += size, to += size; from < to; from /= 2, to /= 2) {
                            if (from % 2 == 1) {
                                if (enter[a[from]] < enter[lca]) {
                                    lca = a[from];
                                }
                                from++;
                            }
                            if (to % 2 == 1) {
                                --to;
                                if (enter[a[to]] < enter[lca]) {
                                    lca = a[to];
                                }
                            }
                        }
                        return lca;
                    }
                }

                private boolean isParent(int p, int u) {
                    return enter[p] <= enter[u] && leave[p] >= leave[u];
                }

                private SegmentTree st = new SegmentTree();

                Path unitePaths(Path p1, Path p2) {
                    if (p1 == null || p2 == null) {
                        return null;
                    }
                    if (!p1.isVertical() && !p2.isVertical()) {
                        if (p1.lca != p2.lca) {
                            return null;
                        }
                        int v1 = isParent(p1.v1, p2.v1) ? p2.v1 : p1.v1;
                        int v2 = isParent(p1.v2, p2.v2) ? p2.v2 : p1.v2;
                        for (int u : new int[]{p1.v1, p1.v2, p2.v1, p2.v2}) {
                            if (!isParent(u, v1) && !isParent(u, v2)) {
                                return null;
                            }
                        }
                        return new Path(v1, v2, p1.lca);
                    }
                    int lca = 0;
                    if (!p1.isVertical()) {
                        lca = p1.lca;
                    }
                    if (!p2.isVertical()) {
                        lca = p2.lca;
                    }
                    for (int u : new int[]{p1.v1, p1.v2}) {
                        for (int v : new int[]{p2.v1, p2.v2}) {
                            if (isParent(u, v) || isParent(v, u)) {
                                continue;
                            }
                            int l = st.getLCA(u, v);
                            if (lca == 0) {
                                lca = l;
                            }
                            if (l != lca) {
                                return null;
                            }
                        }
                    }
                    if (lca == 0) {
                        int v1 = isParent(p1.v1, p2.v1) ? p1.v1 : p2.v1;
                        int v2 = isParent(p1.v2, p2.v2) ? p2.v2 : p1.v2;
                        return new Path(v1, v2, v1);
                    }
                    int v1 = leave[p2.getLeft()] < leave[p1.getLeft()] ? p2.getLeft() : p1.getLeft();
                    int v2 = enter[p2.getRight()] > enter[p1.getRight()] ? p2.getRight() : p1.getRight();
                    for (int u : new int[]{p1.v1, p1.v2, p2.v1, p2.v2}) {
                        if (!isParent(u, v1) && !isParent(u, v2)) {
                            return null;
                        }
                        if (enter[u] < enter[lca]) {
                            return null;
                        }
                    }
                    return new Path(v1, v2, lca);
                }
            }
            final LCA lca = new LCA();
            int[] pReverse = new int[n];
            for (int i = 1; i <= n; i++) {
                pReverse[p[i]] = i;
            }
            class SegmentTree {
                private int size = 1;
                {
                    while (size <= n) {
                        size *= 2;
                    }
                }
                private Path[] a = new Path[2 * size];
                {
                    for (int i = 0; i < n; i++) {
                        a[size + i] = new Path(pReverse[i], pReverse[i], pReverse[i]);
                    }
                    for (int i = size - 1; i > 0; i--) {
                        a[i] = lca.unitePaths(a[2 * i], a[2 * i + 1]);
                    }
                }

                private void swap(int u, int v) {
                    int pu = p[u];
                    int pv = p[v];
                    p[u] = pv;
                    p[v] = pu;
                    pReverse[pv] = u;
                    pReverse[pu] = v;
                    Path pathU = a[size + pu];
                    Path pathV = a[size + pv];
                    a[size + pu] = pathV;
                    a[size + pv] = pathU;
                    for (pu = pu + size >> 1, pv = pv + size >> 1; pu > 0; pu /= 2, pv /= 2) {
                        a[pu] = lca.unitePaths(a[2 * pu], a[2 * pu + 1]);
                        if (pv != pu) {
                            a[pv] = lca.unitePaths(a[2 * pv], a[2 * pv + 1]);
                        }
                    }
                }

                private int getMex() {
                    int i = 1, l = size;
                    while (a[i] == null) {
                        i *= 2;
                        l /= 2;
                    }
                    Path p = a[i];
                    int mex = l;
                    i = 2 * i + 2;
                    while (l > 1) {
                        Path r = lca.unitePaths(p, a[i]);
                        l /= 2;
                        if (r == null) {
                            i *= 2;
                            continue;
                        }
                        i = 2 * i + 2;
                        p = r;
                        mex += l;
                    }
                    return mex;
                }
            }
            SegmentTree st = new SegmentTree();
            int q = input.nextInt();
            for (int i = 0; i < q; i++) {
                if (input.nextInt() == 2) {
                    writer.println(st.getMex());
                } else {
                    st.swap(input.nextInt(), input.nextInt());
                }
            }
        }
    }

    interface Input extends Closeable {
        String next() throws IOException;

        default int nextInt() throws IOException {
            return Integer.parseInt(next());
        }

        default long nextLong() throws IOException {
            return Long.parseLong(next());
        }
    }

    private static class StandardInput implements Input {
        private final BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));

        private StringTokenizer stringTokenizer;

        @Override
        public void close() throws IOException {
            reader.close();
        }

        @Override
        public String next() throws IOException {
            if (stringTokenizer == null || !stringTokenizer.hasMoreTokens()) {
                stringTokenizer = new StringTokenizer(reader.readLine());
            }
            return stringTokenizer.nextToken();
        }
    }
}

import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.io.PrintWriter;
import java.util.StringTokenizer;

/**
 * @author Don Li
 */
public class MaxMex {

    int N = (int) 2e5 + 10;
    int LOG = 20;

    int n;
    int[] val = new int[N], par = new int[N], deg = new int[N];
    int[][] chd = new int[N][];
    int[] val_to_nid = new int[N];

    int timer = 0;
    int[] tin = new int[N], tout = new int[N];
    int[][] anc = new int[N][LOG];

    Node[] tree = new Node[N * 4];

    int ans;
    Node prev;

    void solve() {
        n = in.nextInt();
        for (int i = 0; i < n; i++) val[i] = in.nextInt();
        par[0] = -1;
        for (int i = 1; i < n; i++) {
            par[i] = in.nextInt() - 1;
            deg[par[i]]++;
        }
        for (int i = 0; i < n; i++) chd[i] = new int[deg[i]];
        for (int i = 1; i < n; i++) chd[par[i]][--deg[par[i]]] = i;
        for (int i = 0; i < n; i++) val_to_nid[val[i]] = i;

        dfs(0, 0);

        build_tree(0, 0, n);

        int Q = in.nextInt();
        while (Q-- > 0) {
            int type = in.nextInt();
            if (type == 1) {
                // swap the values and do point updates in the segment tree
                int i = in.nextInt() - 1, j = in.nextInt() - 1;
                if (i == j) continue;
                swap(i, j);
                update(0, 0, n, val[i]);
                update(0, 0, n, val[j]);
            } else {
                // query the segment tree to find the MEX
                ans = 1;
                prev = new Node(val_to_nid[0], val_to_nid[0], val_to_nid[0]);
                find_mex(0, 0, n);
                out.println(ans);
            }
        }
    }

    void swap(int i, int j) {
        int tmp = val[i];
        val[i] = val[j];
        val[j] = tmp;
        val_to_nid[val[i]] = i;
        val_to_nid[val[j]] = j;
    }

    void find_mex(int k, int l, int r) {
        Node res = merge(prev, tree[k]);
        if (!res.bad()) {
            ans = r;
            prev = res;
            return;
        }

        if (r - l > 1) {
            int m = (l + r) >> 1;
            find_mex(2 * k + 1, l, m);
            if (ans == m) {
                find_mex(2 * k + 2, m, r);
            }
        }
    }

    void update(int k, int l, int r, int i) {
        if (r - l == 1) {
            tree[k].g = tree[k].a = tree[k].b = val_to_nid[i];
            return;
        }

        int m = (l + r) >> 1;
        if (i < m) update(2 * k + 1, l, m, i);
        else update(2 * k + 2, m, r, i);
        tree[k] = merge(tree[2 * k + 1], tree[2 * k + 2]);
    }

    void build_tree(int k, int l, int r) {
        if (r - l == 1) {
            tree[k] = new Node(val_to_nid[l], val_to_nid[l], val_to_nid[l]);
            return;
        }

        int m = (l + r) >> 1;
        build_tree(2 * k + 1, l, m);
        build_tree(2 * k + 2, m, r);
        tree[k] = merge(tree[2 * k + 1], tree[2 * k + 2]);
    }

    Node merge(Node u, Node v) {
        if (u.bad() || v.bad()) {
            return new Node(-1, -1, -1);
        }
        Node res = new Node(u.a, u.b, u.g);
        res.add(v.a);
        res.add(v.b);
        return res;
    }

    int lca(int u, int v) {
        if (ancestor(u, v)) return u;
        if (ancestor(v, u)) return v;
        for (int i = LOG - 1; i >= 0; i--) {
            if (!ancestor(anc[u][i], v)) u = anc[u][i];
        }
        return anc[u][0];
    }

    boolean ancestor(int u, int v) {
        return tin[u] <= tin[v] && tout[v] <= tout[u];
    }

    void dfs(int u, int p) {
        tin[u] = timer++;
        anc[u][0] = p;
        for (int i = 1; i < LOG; i++) anc[u][i] = anc[anc[u][i - 1]][i - 1];
        for (int v : chd[u]) {
            dfs(v, u);
        }
        tout[u] = timer++;
    }

    boolean is_vertical(int a, int b, int c) {
        return ancestor(a, b) && ancestor(b, c);
    }

    class Node {
        int a, b;
        int g;

        Node(int a, int b, int g) {
            this.a = a;
            this.b = b;
            this.g = g;
        }

        boolean bad() {
            return a < 0 || b < 0;
        }

        void markBad() {
            a = b = -1;
        }

        void add(int x) {
            if (bad()) return;
            if (a == b) {
                b = x;
                g = lca(a, b);
                if (a == g) {
                    int tmp = a; a = b; b = tmp;
                }
            } else {
                if (ancestor(a, x)) {
                    a = x;
                    return;
                }
                if (b == g) {
                    if (is_vertical(b, x, a)) {
                        return;
                    }
                    if (is_vertical(x, b, a)) {
                        g = b = x;
                        return;
                    }
                    g = lca(a, x);
                    if (ancestor(g, b)) {
                        b = x;
                        return;
                    }
                    markBad();
                    return;
                }
                if (ancestor(b, x)) {
                    b = x;
                    return;
                }
                if (is_vertical(g, x, a) || is_vertical(g, x, b)) {
                    return;
                }
                markBad();
            }
        }
    }

    public static void main(String[] args) {
        in = new FastScanner(new BufferedReader(new InputStreamReader(System.in)));
        out = new PrintWriter(System.out);
        new MaxMex().solve();
        out.close();
    }

    static FastScanner in;
    static PrintWriter out;

    static class FastScanner {
        BufferedReader in;
        StringTokenizer st;

        public FastScanner(BufferedReader in) {
            this.in = in;
        }

        public String nextToken() {
            while (st == null || !st.hasMoreTokens()) {
                try {
                    st = new StringTokenizer(in.readLine());
                } catch (IOException e) {
                    e.printStackTrace();
                }
            }
            return st.nextToken();
        }

        public int nextInt() {
            return Integer.parseInt(nextToken());
        }

        public long nextLong() {
            return Long.parseLong(nextToken());
        }

        public double nextDouble() {
            return Double.parseDouble(nextToken());
        }
    }
}

