                level[u]=++cur;
                level[v]=++cur;
            }
            else if(level[u]==0)
            {
                level[u]=++cur;
                rev++; sb.append(pairs[i].id+1).append(" ");
            }
            else if(level[v]==0)
            {
                level[v]=++cur;
            }
            else
            {
                if(level[v]<level[u])
                {
                    rev++;
                    sb.append(pairs[i].id+1).append(" ");
                }
            }
        }

        System.out.println(ans+" "+rev);
        System.out.println(sb);
    }
}

